#!/usr/bin/env node
'use strict'

/**
 * setup-telegram-bot.js
 *
 * One-time setup for the Telegram bot webhook substrate.
 *
 * Run with:
 *   node backend/scripts/setup-telegram-bot.js \
 *     --token <bot_token_from_BotFather> \
 *     --your-user-id <telegram_user_id> \
 *     [--webhook-url https://api.admin.ecodia.au] \
 *     [--secret <auto-generated if omitted>]
 *
 * What it does:
 *   1. Stores creds.telegram_bot in kv_store as
 *      {bot_token, webhook_secret, allowed_user_ids: [your_user_id]}
 *   2. Calls Telegram's setWebhook API to point at
 *      https://api.admin.ecodia.au/api/webhooks/telegram/<secret>
 *      with the X-Telegram-Bot-Api-Secret-Token header check enabled
 *   3. Verifies via getWebhookInfo
 *
 * How to find your_user_id:
 *   - Open Telegram, message @userinfobot
 *   - It replies with your user ID (numeric)
 *   OR
 *   - Message your bot once, then run:
 *     curl "https://api.telegram.org/bot<TOKEN>/getUpdates"
 *     Look for message.from.id in the response
 *
 * Authored 2026-05-16 (sleep-shift, pre-staging for Tate's nap wake-up).
 */

const path = require('path')
const crypto = require('crypto')

require('dotenv').config({ path: path.join(__dirname, '..', '.env') })

const { Pool } = require('pg')

const args = process.argv.slice(2)
function getArg(flag) {
  const i = args.indexOf(flag)
  return i >= 0 ? args[i + 1] : null
}

const token = getArg('--token') || process.env.TELEGRAM_BOT_TOKEN
const yourUserId = getArg('--your-user-id') || process.env.TELEGRAM_USER_ID
const webhookUrl = getArg('--webhook-url') || 'https://api.admin.ecodia.au'
const providedSecret = getArg('--secret')

if (!token) {
  console.error('ERROR: --token <bot_token> required (or TELEGRAM_BOT_TOKEN env var)')
  console.error('Get the bot token by messaging @BotFather on Telegram, /newbot, follow prompts.')
  process.exit(2)
}
if (!yourUserId) {
  console.error('ERROR: --your-user-id <numeric_telegram_user_id> required (or TELEGRAM_USER_ID env var)')
  console.error('Get yours by messaging @userinfobot on Telegram.')
  process.exit(2)
}
if (!process.env.DATABASE_URL) {
  console.error('ERROR: DATABASE_URL not set. Source backend/.env.')
  process.exit(2)
}

const secret = providedSecret || crypto.randomBytes(24).toString('hex')
const fullWebhookUrl = `${webhookUrl.replace(/\/$/, '')}/api/webhooks/telegram/${secret}`

console.log('=== Telegram bot setup ===')
console.log('Bot token:        ', token.slice(0, 12) + '...' + token.slice(-4))
console.log('Allowed user ID:  ', yourUserId)
console.log('Webhook URL:      ', fullWebhookUrl)
console.log('Webhook secret:   ', secret.slice(0, 8) + '...')
console.log('')

;(async () => {
  // Step 1: store creds in kv_store
  const pool = new Pool({ connectionString: process.env.DATABASE_URL })
  const credValue = JSON.stringify({
    bot_token: token,
    webhook_secret: secret,
    allowed_user_ids: [String(yourUserId)],
    provisioned_at: new Date().toISOString(),
  })
  try {
    await pool.query(
      `INSERT INTO kv_store (key, value, updated_at)
       VALUES ('creds.telegram_bot', $1, NOW())
       ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW()`,
      [credValue]
    )
    console.log('[1/3] kv_store.creds.telegram_bot upserted')
  } catch (err) {
    console.error('[1/3] kv_store upsert FAILED:', err.message)
    await pool.end()
    process.exit(1)
  }
  await pool.end()

  // Step 2: call Telegram setWebhook
  console.log('[2/3] calling Telegram setWebhook...')
  try {
    const params = new URLSearchParams()
    params.set('url', fullWebhookUrl)
    params.set('secret_token', secret)
    params.set('allowed_updates', '["message","edited_message"]')
    params.set('drop_pending_updates', 'true')
    const resp = await fetch(`https://api.telegram.org/bot${token}/setWebhook`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: params.toString(),
    })
    const body = await resp.json()
    if (resp.status === 200 && body.ok) {
      console.log('      setWebhook OK:', body.description || body.result)
    } else {
      console.error('      setWebhook FAILED:', resp.status, body)
      process.exit(1)
    }
  } catch (err) {
    console.error('      setWebhook FETCH FAILED:', err.message)
    process.exit(1)
  }

  // Step 3: verify via getWebhookInfo
  console.log('[3/3] verifying via getWebhookInfo...')
  try {
    const resp = await fetch(`https://api.telegram.org/bot${token}/getWebhookInfo`)
    const body = await resp.json()
    if (resp.status === 200 && body.ok) {
      const info = body.result
      console.log('      URL:                ', info.url)
      console.log('      Pending updates:    ', info.pending_update_count)
      console.log('      Has custom cert:    ', info.has_custom_certificate)
      console.log('      Last error message: ', info.last_error_message || '(none)')
      console.log('      Allowed updates:    ', info.allowed_updates ? info.allowed_updates.join(', ') : '(default)')
      if (info.url === fullWebhookUrl) {
        console.log('')
        console.log('SUCCESS - Telegram bot is wired to', fullWebhookUrl)
        console.log('Test it: open Telegram, find your bot, send a message.')
        console.log('Expect: a new Claude Code chat tab opens on Corazon within ~5s and replies via the bot.')
      } else {
        console.warn('WARNING: webhook URL mismatch. Got:', info.url, 'expected:', fullWebhookUrl)
      }
    } else {
      console.error('      getWebhookInfo FAILED:', resp.status, body)
      process.exit(1)
    }
  } catch (err) {
    console.error('      getWebhookInfo FETCH FAILED:', err.message)
    process.exit(1)
  }
})()
